namespace LiteDB.Engine
{
    /// <summary>
    /// Represents a page address inside a page structure - index could be byte offset position OR index in a list (6 bytes)
    /// </summary>
    [DebuggerStepThrough]
    internal struct PageAddress
    {
        public const int SIZE = 5;

        public static PageAddress Empty = new PageAddress(uint.MaxValue, byte.MaxValue);

        /// <summary>
        /// PageID (4 bytes)
        /// </summary>
        public readonly uint PageID;

        /// <summary>
        /// Page Segment index inside page (1 bytes)
        /// </summary>
        public readonly byte Index;

        /// <summary>
        /// Returns true if this PageAdress is empty value
        /// </summary>
        public bool IsEmpty => this.PageID == uint.MaxValue && this.Index == byte.MaxValue;

        public override bool Equals(object obj)
        {
            var other = (PageAddress)obj;

            return this.PageID == other.PageID && this.Index == other.Index;
        }

        public static bool operator ==(PageAddress lhs, PageAddress rhs)
        {
            return lhs.PageID == rhs.PageID && lhs.Index == rhs.Index;
        }

        public static bool operator !=(PageAddress lhs, PageAddress rhs)
        {
            return !(lhs == rhs);
        }

        public override int GetHashCode()
        {
            unchecked
            {
                int hash = 17;
                hash = hash * 23 + (int)this.PageID;
                hash = hash * 23 + this.Index;
                return hash;
            }
        }

        public PageAddress(uint pageID, byte index)
        {
            this.PageID = pageID;
            this.Index = index;
        }

        public override string ToString()
        {
            return this.IsEmpty ? "(empty)" : this.PageID.ToString().PadLeft(4, '0') + ":" + this.Index.ToString().PadLeft(2, '0');
        }

        public BsonValue ToBsonValue()
        {
            if (this.IsEmpty) return BsonValue.Null;

            return new BsonDocument
            {
                ["pageID"] = (int)this.PageID,
                ["index"] = (int)this.Index
            };
        }
    }
}

namespace LiteDB.Engine
{
    /// <summary>
    /// Represent page buffer to be read/write using FileMemory
    /// </summary>
    internal class PageBuffer : BufferSlice
    {
        /// <summary>
        /// Get, on initialize, a unique ID in all database instance for this PageBufer. Is a simple global incremented counter
        /// </summary>
        public readonly int UniqueID;

        /// <summary>
        /// Get/Set page position. If page are writable, this postion CAN be MaxValue (has not defined position yet)
        /// </summary>
        public long Position;

        /// <summary>
        /// Get/Set page bytes origin (data/log)
        /// </summary>
        public FileOrigin Origin;

        /// <summary>
        /// Get/Set how many read-share threads are using this page. -1 means 1 thread are using as writable
        /// </summary>
        public int ShareCounter;

        /// <summary>
        /// Get/Set timestamp from last request
        /// </summary>
        public long Timestamp;

        public PageBuffer(byte[] buffer, int offset, int uniqueID)
            : base(buffer, offset, PAGE_SIZE)
        {
            this.UniqueID = uniqueID;
            this.Position = long.MaxValue;
            this.Origin = FileOrigin.None;
            this.ShareCounter = 0;
            this.Timestamp = 0;
        }

        /// <summary>
        /// Release this page - decrement ShareCounter
        /// </summary>
        public void Release()
        {
            ENSURE(this.ShareCounter > 0, "share counter must be > 0 in Release()");

            Interlocked.Decrement(ref this.ShareCounter);
        }

#if DEBUG
        ~PageBuffer()
        {
            ENSURE(this.ShareCounter == 0, $"share count must be 0 in destroy PageBuffer (current: {this.ShareCounter})");
        }
#endif

        public override string ToString()
        {
            var p = this.Position == long.MaxValue ? "<empty>" : this.Position.ToString();
            var s = this.ShareCounter == BUFFER_WRITABLE ? "<writable>" : this.ShareCounter.ToString();
            var pageID = this.ReadUInt32(0);
            var pageType = this[4];

            return $"ID: {this.UniqueID} - Position: {p}/{this.Origin} - Shared: {s} - ({base.ToString()}) :: Content: [{pageID.ToString("0:0000")}/{(PageType)pageType}]";
        }

        public unsafe bool IsBlank()
        {
            fixed (byte* arrayPtr = this.Array)
            {
                ulong* ptr = (ulong*)(arrayPtr + this.Offset);

                return *ptr == 0UL && *(ptr + 1) == 0UL;
            }
        }
    }
}

namespace LiteDB.Engine
{
    /// <summary>
    /// Represents a page position after save in disk. Used in WAL files where PageID do not match with PagePosition
    /// </summary>
    internal struct PagePosition
    {
        public static PagePosition Empty => new PagePosition(uint.MaxValue, long.MaxValue);

        /// <summary>
        /// PageID (4 bytes)
        /// </summary>
        public uint PageID;

        /// <summary>
        /// Position in disk
        /// </summary>
        public long Position;

        /// <summary>
        /// Checks if current PagePosition is empty value
        /// </summary>
        public bool IsEmpty => this.PageID == uint.MaxValue && this.Position == long.MaxValue;

        public override bool Equals(object obj)
        {
            var other = (PagePosition)obj;

            return this.PageID == other.PageID && this.Position == other.PageID;
        }

        public override int GetHashCode()
        {
            unchecked
            {
                int hash = 17;
                hash = hash * 23 + (int)this.PageID;
                hash = hash * 23 + (int)this.Position;
                return hash;
            }
        }

        public PagePosition(uint pageID, long position)
        {
            this.PageID = pageID;
            this.Position = position;
        }

        public override string ToString()
        {
            return this.IsEmpty ? "----:----" :
                (this.PageID == uint.MaxValue ? "----" : this.PageID.ToString()) + ":" + this.Position.ToString();
        }
    }
}

