namespace LiteDB.Engine
{
    internal class SysDump : SystemCollection
    {
        private readonly HeaderPage _header;
        private readonly TransactionMonitor _monitor;

        public SysDump(HeaderPage header, TransactionMonitor monitor) : base("$dump")
        {
            _header = header;
            _monitor = monitor;
        }

        public override IEnumerable<BsonDocument> Input(BsonValue options)
        {
            var pageID = GetOption(options, "pageID");

            return this.DumpPages(pageID == null ? null : (uint?)pageID.AsInt32);
        }

        private IEnumerable<BsonDocument> DumpPages(uint? pageID)
        {
            var collections = _header.GetCollections().ToDictionary(x => x.Value, x => x.Key);

            // get any transaction from current thread ID
            var transaction = _monitor.GetThreadTransaction();

            var snapshot = transaction.CreateSnapshot(LockMode.Read, "$", false);

            var start = pageID.HasValue ? pageID.Value : 0;
            var end = pageID.HasValue ? pageID.Value : _header.LastPageID;

            for (uint i = start; i <= Math.Min(end, _header.LastPageID); i++)
            {
                var page = snapshot.GetPage<BasePage>(i, out var origin, out var position, out var walVersion);

                var doc = new BsonDocument
                {
                    ["pageID"] = (int)page.PageID,
                    ["pageType"] = page.PageType.ToString(),
                    ["_position"] = position,
                    ["_origin"] = origin.ToString(),
                    ["_version"] = walVersion,
                    ["prevPageID"] = (int)page.PrevPageID,
                    ["nextPageID"] = (int)page.NextPageID,
                    ["slot"] = (int)page.PageListSlot,
                    ["collection"] = collections.GetOrDefault(page.ColID, "-"),
                    ["itemsCount"] = (int)page.ItemsCount,
                    ["freeBytes"] = page.FreeBytes,
                    ["usedBytes"] = (int)page.UsedBytes,
                    ["fragmentedBytes"] = (int)page.FragmentedBytes,
                    ["nextFreePosition"] = (int)page.NextFreePosition,
                    ["highestIndex"] = (int)page.HighestIndex
                };

                if (page.PageType == PageType.Collection)
                {
                    var collectionPage = new CollectionPage(page.Buffer);
                    doc["dataPageList"] = new BsonArray(collectionPage.FreeDataPageList.Select(x => new BsonValue((int)x)));
                    doc["indexes"] = new BsonArray(collectionPage.GetCollectionIndexes().Select(x => new BsonDocument
                    {
                        ["slot"] = (int)x.Slot,
                        ["empty"] = x.IsEmpty,
                        ["indexType"] = (int)x.IndexType,
                        ["name"] = x.Name,
                        ["expression"] = x.Expression,
                        ["unique"] = x.Unique,
                        ["head"] = x.Head.ToBsonValue(),
                        ["tail"] = x.Tail.ToBsonValue(),
                        ["maxLevel"] = (int)x.MaxLevel,
                        ["freeIndexPageList"] = (int)x.FreeIndexPageList,                        
                    }));
                }

                if (pageID.HasValue) doc["buffer"] = page.Buffer.ToArray();

                yield return doc;

                transaction.Safepoint();
            }
        }
    }
}

namespace LiteDB.Engine
{
    internal class SysFile : SystemCollection
    {
        private Dictionary<string, SystemCollection> _formats = new Dictionary<string, SystemCollection>(StringComparer.OrdinalIgnoreCase)
        {
            ["json"] = new SysFileJson(),
            ["csv"] = new SysFileCsv()
        };

        public SysFile() : base("$file")
        {
        }

        public override IEnumerable<BsonDocument> Input(BsonValue options)
        {
            var format = this.GetFormat(options);

            if (_formats.TryGetValue(format, out var factory))
            {
                return factory.Input(options);
            }

            throw new LiteException(0, $"Unknow file format in $file: `{format}`");
        }

        public override int Output(IEnumerable<BsonDocument> source, BsonValue options)
        {
            var format = this.GetFormat(options);

            if (_formats.TryGetValue(format, out var factory))
            {
                return factory.Output(source, options);
            }

            throw new LiteException(0, $"Unknow file format in $file: `{format}`");
        }

        private string GetFormat(BsonValue options)
        {
            var filename = GetOption(options, "filename")?.AsString ?? throw new LiteException(0, $"Collection $file requires string as 'filename' or a document field 'filename'");
            var format = GetOption(options, "format", Path.GetExtension(filename)).AsString;

            return format.StartsWith(".") ? format.Substring(1) : format;
        }
    }
}

namespace LiteDB.Engine
{
    internal class SysFileCsv : SystemCollection
    {
        private readonly static IFormatProvider _numberFormat = CultureInfo.InvariantCulture.NumberFormat;

        public SysFileCsv() : base("$file_csv")
        {
        }

        public override IEnumerable<BsonDocument> Input(BsonValue options)
        {
            var filename = GetOption(options, "filename")?.AsString ?? throw new LiteException(0, $"Collection ${this.Name} requires string as 'filename' or a document field 'filename'");
            var encoding = GetOption(options, "encoding", "utf-8").AsString;
            var delimiter = GetOption(options, "delimiter", ",").AsString[0];

            // read header (or first line as header)
            var header = new List<string>();

            if (options.IsDocument && options["header"].IsArray)
            {
                header.AddRange(options["header"].AsArray.Select(x => x.AsString));
            }

            using (var fs = new FileStream(filename, FileMode.Open, FileAccess.Read, FileShare.ReadWrite))
            {
                using (var reader = new StreamReader(fs, Encoding.GetEncoding(encoding)))
                {
                    // if not header declared, use first line as header fields
                    if (header.Count == 0)
                    {
                        while (true)
                        {
                            var key = this.ReadString(reader, delimiter, out var newLine);

                            if (key == null) break;

                            header.Add(key);

                            if (newLine) break;
                        }
                    }

                    // read all results
                    var index = 0;
                    var doc = new BsonDocument();

                    while(true)
                    {
                        var value = this.ReadString(reader, delimiter, out var newLine);

                        if (value == null) yield break;

                        if (index < header.Count)
                        {
                            var key = header[index++];
                            doc[key] = value;
                        }

                        if (newLine)
                        {
                            yield return doc;

                            doc = new BsonDocument();
                            index = 0;
                        }
                    }
                }
            }
        }

        public override int Output(IEnumerable<BsonDocument> source, BsonValue options)
        {
            var filename = GetOption(options, "filename")?.AsString ?? throw new LiteException(0, "Collection $file_json requires string as 'filename' or a document field 'filename'");
            var overwritten = GetOption(options, "overwritten", false).AsBoolean;
            var encoding = GetOption(options, "encoding", "utf-8").AsString;
            var delimiter = GetOption(options, "delimiter", ",").AsString[0];
            var header = GetOption(options, "header", true).AsBoolean;

            var index = 0;

            IList<string> headerFields = null;
            FileStream fs = null;
            StreamWriter writer = null;

            try
            {
                foreach (var doc in source)
                {
                    if (index++ == 0)
                    {
                        fs = new FileStream(filename, overwritten ? FileMode.OpenOrCreate : FileMode.CreateNew);
                        writer = new StreamWriter(fs, Encoding.GetEncoding(encoding));

                        headerFields = doc.Keys.ToList();

                        // print file header
                        if (header)
                        {
                            var idxHeader = 0;

                            foreach (var elem in doc)
                            {
                                if (idxHeader++ > 0) writer.Write(delimiter);
                                writer.Write(elem.Key);
                            }

                            writer.WriteLine();
                        }
                    }
                    else
                    {
                        writer.WriteLine();
                    }

                    var idxValue = 0;

                    foreach(var field in headerFields)
                    {
                        var value = doc[field];

                        if (idxValue++ > 0) writer.Write(delimiter);

                        this.WriteValue(value, writer);
                    }
                }

                if (index > 0)
                {
                    writer.Flush();
                }
            }
            finally
            {
                if (writer != null) writer.Dispose();
                if (fs != null) fs.Dispose();
            }

            return index;
        }

        private void WriteValue(BsonValue value, StreamWriter writer)
        {
            switch (value.Type)
            {
                case BsonType.MinValue:
                case BsonType.Null:
                case BsonType.Document:
                case BsonType.Array:
                case BsonType.MaxValue:
                    writer.Write("null");
                    break;
                case BsonType.Int64:
                    writer.Write(value.AsInt64.ToString(CultureInfo.InvariantCulture.NumberFormat));
                    break;
                case BsonType.Decimal:
                    writer.Write(value.AsDecimal.ToString(CultureInfo.InvariantCulture.NumberFormat));
                    break;
                case BsonType.Binary:
                    writer.Write($"\"{Convert.ToBase64String(value.AsBinary)}\"");
                    break;
                case BsonType.ObjectId:
                    writer.Write($"\"{value.AsObjectId.ToString()}\"");
                    break;
                case BsonType.Guid:
                    writer.Write($"\"{value.AsGuid.ToString()}\"");
                    break;
                case BsonType.DateTime:
                    writer.Write($"\"{value.AsDateTime.ToUniversalTime().ToString("o")}\"");
                    break;
                default:
                    writer.Write(value.ToString());
                    break;
            }
        }

        private string ReadString(TextReader reader, char delimiter, out bool newLine)
        {
            var sb = new StringBuilder();
            var c = reader.Read();

            // eat possible new line before read string
            while(c == '\n' || c == '\r')
            {
                c = reader.Read();
            }

            if (c == -1)
            {
                newLine = true;
                return null;
            }

            // read " string
            if(c == '"')
            {
                var last = c;

                while(c != -1)
                {
                    c = reader.Read();

                    if (c == '"')
                    {
                        var next = reader.Read();

                        if (next == '"')
                        {
                            sb.Append('"');
                            continue;
                        }
                        else
                        {
                            c = next;
                            break;
                        }
                    }

                    sb.Append((char)c);
                    last = c;
                }
            }
            else
            {
                while(!(c == '\n' || c == '\r' || c == delimiter || c == -1))
                {
                    sb.Append((char)c);
                    c = reader.Read();
                }
            }

            newLine = (c == '\n' || c == '\r');

            return sb.ToString();
        }
    }
}

namespace LiteDB.Engine
{
    internal class SysFileJson : SystemCollection
    {
        public SysFileJson() : base("$file_json")
        {
        }

        public override IEnumerable<BsonDocument> Input(BsonValue options)
        {
            var filename = GetOption(options, "filename")?.AsString ?? throw new LiteException(0, $"Collection ${this.Name} requires string as 'filename' or a document field 'filename'");
            var encoding = GetOption(options, "encoding", "utf-8").AsString;

            using (var fs = new FileStream(filename, FileMode.Open, FileAccess.Read, FileShare.ReadWrite))
            {
                using (var reader = new StreamReader(fs, Encoding.GetEncoding(encoding)))
                {
                    var json = new JsonReader(reader);

                    var source = json.DeserializeArray()
                        .Select(x => x.AsDocument);

                    // read documents inside file and return one-by-one
                    foreach (var doc in source)
                    {
                        yield return doc;
                    }
                }
            }
        }

        public override int Output(IEnumerable<BsonDocument> source, BsonValue options)
        {
            var filename = GetOption(options, "filename")?.AsString ?? throw new LiteException(0, "Collection $file_json requires string as filename or a document field 'filename'");
            var pretty = GetOption(options, "pretty", false).AsBoolean;
            var indent = GetOption(options, "indent", 4).AsInt32;
            var encoding = GetOption(options, "encoding", "utf-8").AsString;
            var overwritten = GetOption(options, "overwritten", false).AsBoolean;

            var index = 0;
            FileStream fs = null;
            StreamWriter writer = null;
            JsonWriter json = null;

            try
            {
                foreach (var doc in source)
                {
                    if (index++ == 0)
                    {
                        fs = new FileStream(filename, overwritten ? FileMode.OpenOrCreate : FileMode.CreateNew);
                        writer = new StreamWriter(fs, Encoding.GetEncoding(encoding));
                        json = new JsonWriter(writer)
                        {
                            Pretty = pretty,
                            Indent = indent
                        };

                        writer.WriteLine("[");
                    }
                    else
                    {
                        writer.WriteLine(",");
                    }

                    json.Serialize(doc);
                }

                if (index > 0)
                {
                    writer.WriteLine();
                    writer.Write("]");
                    writer.Flush();
                }
            }
            finally
            {
                if (writer != null) writer.Dispose();
                if (fs != null) fs.Dispose();
            }

            return index;
        }
    }
}

namespace LiteDB.Engine
{
    public partial class LiteEngine
    {
        private IEnumerable<BsonDocument> SysIndexes()
        {
            // get any transaction from current thread ID
            var transaction = _monitor.GetThreadTransaction();

            foreach (var collection in _header.GetCollections())
            {
                var snapshot = transaction.CreateSnapshot(LockMode.Read, collection.Key, false);

                foreach(var index in snapshot.CollectionPage.GetCollectionIndexes())
                {
                    yield return new BsonDocument
                    {
                        ["collection"] = collection.Key,
                        ["name"] = index.Name,
                        ["expression"] = index.Expression,
                        ["unique"] = index.Unique,
                        ["maxLevel"] = (int)index.MaxLevel
                    };
                }
            }
        }
    }
}

namespace LiteDB.Engine
{
    public partial class LiteEngine
    {
        private IEnumerable<BsonDocument> SysOpenCursors()
        {
            foreach (var transaction in _monitor.Transactions)
            {
                foreach(var cursor in transaction.OpenCursors)
                {
                    yield return new BsonDocument
                    {
                        ["threadID"] = transaction.ThreadID,
                        ["transactionID"] = (int)transaction.TransactionID,
                        ["elapsedMS"] = (int)cursor.Elapsed.ElapsedMilliseconds,
                        ["collection"] = cursor.Collection,
                        ["mode"] = cursor.Query.ForUpdate ? "write" : "read",
                        ["sql"] = cursor.Query.ToSQL(cursor.Collection).Replace(Environment.NewLine, " "),
                        ["running"] = cursor.Elapsed.IsRunning,
                        ["fetched"] = cursor.Fetched
                    };
                }
            }
        }
    }
}

namespace LiteDB.Engine
{
    internal class SysPageList : SystemCollection
    {
        private readonly HeaderPage _header;
        private readonly TransactionMonitor _monitor;
        private Dictionary<uint, string> _collections;

        public SysPageList(HeaderPage header, TransactionMonitor monitor) : base("$page_list")
        {
            _header = header;
            _monitor = monitor;
        }

        public override IEnumerable<BsonDocument> Input(BsonValue options)
        {
            var pageID = GetOption(options, "pageID");

            // get any transaction from current thread ID
            var transaction = _monitor.GetThreadTransaction();
            var snapshot = transaction.CreateSnapshot(LockMode.Read, "$", false);

            _collections = _header.GetCollections().ToDictionary(x => x.Value, x => x.Key);

            var result = pageID != null ?
                this.GetList((uint)pageID.AsInt32, null, transaction, snapshot) :
                this.GetAllList(transaction, snapshot);

            foreach (var page in result)
            {
                yield return page;
            }
        }

        private IEnumerable<BsonDocument> GetAllList(TransactionService transaction, Snapshot snapshot)
        {
            // get empty page list, from header
            foreach (var page in this.GetList(_header.FreeEmptyPageList, null, transaction, snapshot))
            {
                yield return page;
            }

            // get lists from data pages/index list
            foreach (var collection in _collections)
            {
                var snap = transaction.CreateSnapshot(LockMode.Read, collection.Value, false);

                for (var slot = 0; slot < PAGE_FREE_LIST_SLOTS; slot++)
                {
                    var result = this.GetList(snap.CollectionPage.FreeDataPageList[slot], null, transaction, snap);

                    foreach (var page in result)
                    {
                        yield return page;
                    }
                }

                var indexes = snap.CollectionPage.GetCollectionIndexes().ToArray();

                foreach (var index in indexes)
                {
                    var result = this.GetList(index.FreeIndexPageList, index.Name, transaction, snap);

                    foreach (var page in result)
                    {
                        yield return page;
                    }

                }
            }
        }

        private IEnumerable<BsonDocument> GetList(uint pageID, string indexName, TransactionService transaction, Snapshot snapshot)
        {
            if (pageID == uint.MaxValue) yield break;

            var page = snapshot.GetPage<BasePage>(pageID);

            while (page != null)
            {
                _collections.TryGetValue(page.ColID, out var collection);

                yield return new BsonDocument
                {
                    ["pageID"] = (int)page.PageID,
                    ["pageType"] = page.PageType.ToString(),
                    ["slot"] = (int)page.PageListSlot,
                    ["collection"] = collection,
                    ["index"] = indexName,
                    ["freeBytes"] = page.FreeBytes,
                    ["itemsCount"] = (int)page.ItemsCount
                };

                if (page.NextPageID == uint.MaxValue) break;

                transaction.Safepoint();

                page = snapshot.GetPage<BasePage>(page.NextPageID);
            }
        }
    }
}

namespace LiteDB.Engine
{
    /// <summary>
    /// This class implement $query experimental system function to run sub-queries. It's experimental only - possible not be present in final release
    /// </summary>
    internal class SysQuery : SystemCollection
    {
        private readonly ILiteEngine _engine;

        public SysQuery(ILiteEngine engine) : base("$query")
        {
            _engine = engine; 
        }

        public override IEnumerable<BsonDocument> Input(BsonValue options)
        {
            var query = options?.AsString ?? throw new LiteException(0, $"Collection $query(sql) requires `sql` string parameter");

            var sql = new SqlParser(_engine, new Tokenizer(query), null);

            using (var reader = sql.Execute())
            {
                while(reader.Read())
                {
                    var value = reader.Current;

                    yield return value.IsDocument ? value.AsDocument : new BsonDocument { ["expr"] = value };
                }
            }
        }
    }
}

